#include "thermistor.h"
#include <Arduino.h>
#include <math.h>
#define THERM_PIN 34
#define SERIES_R 10000
#define NOMINAL_R 10000
#define NOMINAL_T 25
#define B_COEFF 3950
static float _t=0;static int _raw=0;static unsigned long _l=0;
void thermistor_setup(){Serial.println("[therm] OK");}
void thermistor_loop(){if(millis()-_l<1000)return;_l=millis();_raw=analogRead(THERM_PIN);float r=SERIES_R/(4095.0/_raw-1.0);float s=r/NOMINAL_R;s=log(s);s/=B_COEFF;s+=1.0/(NOMINAL_T+273.15);_t=1.0/s-273.15;}
float thermistor_get_temperature(){return _t;}
int thermistor_get_raw(){return _raw;}
